use std::path::Path;

use anyhow::{Context, Result};
use rusqlite::{Connection, params};

use crate::core::{
    Board, BoardState, Column, Priority, Task,
    query_board_by_id, query_columns_by_board, query_priorities, query_tasks_by_board,
    query_all_boards,
};

/// Embedded migration SQL files. Each entry is (migration_id, name, sql).
fn embedded_migrations() -> &'static [Migration] {
    &[Migration {
        id: 1,
        name: "001_initial_schema",
        sql: include_str!("../../migrations/001_initial_schema.sql"),
    }]
}

struct Migration {
    id: i64,
    name: &'static str,
    sql: &'static str,
}

/// Database handle wrapping a rusqlite Connection.
pub struct Db {
    conn: Connection,
}

impl Db {
    /// Open a database at the given path.
    ///
    /// Creates parent directories and the DB file if missing, then runs all pending
    /// migrations in order inside a transaction.
    pub fn open(path: &Path) -> Result<Self> {
        // Create parent directories if needed
        if let Some(parent) = path.parent() {
            std::fs::create_dir_all(parent)
                .with_context(|| format!("failed to create directory: {}", parent.display()))?;
        }

        let conn = Connection::open(path)
            .with_context(|| format!("failed to open database: {}", path.display()))?;

        // Run migrations
        run_migrations(&conn)?;

        Ok(Db { conn })
    }

    /// Load the complete state of a board by its ID.
    pub fn load_board_state(&self, board_id: &str) -> Result<BoardState> {
        let board = self.query_board(board_id)?
            .ok_or_else(|| anyhow::anyhow!("board not found: '{}'", board_id))?;
        let columns = self.query_columns(board_id)?;
        let tasks = self.query_tasks(board_id)?;
        let priorities = self.query_priorities()?;

        Ok(BoardState {
            board,
            columns,
            tasks,
            priorities,
        })
    }

    /// List all boards.
    pub fn list_boards(&self) -> Result<Vec<Board>> {
        let mut stmt = self.conn.prepare(query_all_boards())?;
        let boards = stmt.query_map([], |row| {
            Ok(Board {
                id: row.get(0)?,
                name: row.get(1)?,
                created_at: row.get(2)?,
                updated_at: row.get(3)?,
            })
        })?;

        boards.collect::<std::result::Result<Vec<_>, _>>().context("failed to list boards")
    }

    fn query_board(&self, board_id: &str) -> Result<Option<Board>> {
        let mut stmt = self.conn.prepare(query_board_by_id())?;
        let board = stmt.query_map(params![board_id], |row| {
            Ok(Board {
                id: row.get(0)?,
                name: row.get(1)?,
                created_at: row.get(2)?,
                updated_at: row.get(3)?,
            })
        })?;

        let result: Vec<Board> = board.collect::<std::result::Result<Vec<_>, _>>()?;
        Ok(result.into_iter().next())
    }

    fn query_columns(&self, board_id: &str) -> Result<Vec<Column>> {
        let mut stmt = self.conn.prepare(query_columns_by_board())?;
        let columns = stmt.query_map(params![board_id], |row| {
            Ok(Column {
                id: row.get(0)?,
                board_id: row.get(1)?,
                name: row.get(2)?,
                position: row.get(3)?,
                created_at: row.get(4)?,
                updated_at: row.get(5)?,
            })
        })?;

        columns.collect::<std::result::Result<Vec<_>, _>>().context("failed to load columns")
    }

    fn query_tasks(&self, board_id: &str) -> Result<Vec<Task>> {
        let mut stmt = self.conn.prepare(query_tasks_by_board())?;
        let tasks = stmt.query_map(params![board_id], |row| {
            Ok(Task {
                id: row.get(0)?,
                column_id: row.get(1)?,
                title: row.get(2)?,
                description: row.get(3)?,
                priority_id: row.get(4)?,
                position: row.get(5)?,
                created_at: row.get(6)?,
                updated_at: row.get(7)?,
            })
        })?;

        tasks.collect::<std::result::Result<Vec<_>, _>>().context("failed to load tasks")
    }

    fn query_priorities(&self) -> Result<Vec<Priority>> {
        let mut stmt = self.conn.prepare(query_priorities())?;
        let priorities = stmt.query_map([], |row| {
            Ok(Priority {
                id: row.get(0)?,
                name: row.get(1)?,
            })
        })?;

        priorities
            .collect::<std::result::Result<Vec<_>, _>>()
            .context("failed to load priorities")
    }
}

/// Run all pending migrations within a transaction.
fn run_migrations(conn: &Connection) -> Result<()> {
    let migrations = embedded_migrations();
    if migrations.is_empty() {
        return Ok(());
    }

    conn.execute(
        "BEGIN",
        [],
    ).context("failed to begin migration transaction")?;

    let result: Result<()> = (|| {
        // Ensure _migrations table exists before checking applied ones
        // We find the first unapplied migration and create _migrations if needed
        let applied = get_applied_migration_ids(conn)?;

        for migration in migrations {
            if !applied.contains(&migration.id) {
                // _migrations must exist by this point if any migration has been applied.
                // For the very first run, the migration itself creates it.
                conn.execute_batch(migration.sql)
                    .with_context(|| format!("failed to apply migration {}", migration.name))?;
                // Record the migration if _migrations was created by this migration
                // (it will be for the first migration)
                let exists: bool = conn.query_row(
                    "SELECT EXISTS(SELECT 1 FROM _migrations WHERE id = ?1)",
                    params![migration.id],
                    |row| row.get(0),
                ).unwrap_or(false);
                if !exists {
                    conn.execute(
                        "INSERT INTO _migrations (id, name) VALUES (?1, ?2)",
                        params![migration.id, migration.name],
                    ).with_context(|| {
                        format!("failed to record migration {}", migration.name)
                    })?;
                }
            }
        }

        conn.execute("COMMIT", [])
            .context("failed to commit migration transaction")?;
        Ok(())
    })();

    // Rollback on failure
    if result.is_err() {
        let _ = conn.execute("ROLLBACK", []);
    }

    result
}

/// Get the set of already-applied migration IDs.
fn get_applied_migration_ids(conn: &Connection) -> Result<Vec<i64>> {
    // Try to query _migrations; if it doesn't exist, return empty
    let mut stmt = conn.prepare("SELECT id FROM _migrations ORDER BY id");
    match stmt {
        Ok(mut stmt) => {
            let ids = stmt.query_map([], |row| row.get::<_, i64>(0))
                .map(|rows| rows.collect::<std::result::Result<Vec<_>, _>>());
            match ids {
                Ok(Ok(ids)) => Ok(ids),
                _ => Ok(vec![]),
            }
        }
        Err(_) => Ok(vec![]),
    }
}

