// ── Helper to bind SqlParam values for rusqlite ───────────────────────────

fn bind_params<'a>(
    stmt: &'a mut rusqlite::Statement,
    params: &[SqlParam],
) -> std::result::Result<rusqlite::MappedRows<'a, rusqlite::types::FromRows>, rusqlite::Error> {
    let rusqlite_params: Vec<&dyn rusqlite::types::ToSql> = params
        .iter()
        .map(|p| match p {
            SqlParam::Text(s) => s as &dyn rusqlite::types::ToSql,
            SqlParam::Int(i) => i as &dyn rusqlite::types::ToSql,
        })
        .collect();

    stmt.query(rusqlite::params_from_iter(rusqlite_params.iter().copied()))
}

fn exec_with_params(
    conn: &rusqlite::Connection,
    sql: &str,
    params: &[SqlParam],
) -> Result<()> {
    let rusqlite_params: Vec<&dyn rusqlite::types::ToSql> = params
        .iter()
        .map(|p| match p {
            SqlParam::Text(s) => s as &dyn rusqlite::types::ToSql,
            SqlParam::Int(i) => i as &dyn rusqlite::types::ToSql,
        })
        .collect();
    let mut stmt = conn
        .prepare(sql)
        .context("failed to prepare statement")?;
    stmt.execute(rusqlite::params_from_iter(rusqlite_params.iter().copied()))
        .context("failed to execute statement")?;
    Ok(())
}

fn now() -> String {
    chrono::Utc::now().to_rfc3339()
}

fn gen_id() -> String {
    nanoid::nanoid!(10)
}

// ── Board operations ──────────────────────────────────────────────────────

/// Initialize a new board with default columns and priorities.
pub fn init_board(db: &Db, name: &str) -> Result<Board> {
    // Check for duplicate board name
    let existing = db.list_boards().context("failed to list boards")?;
    if existing.iter().any(|b| b.name == name) {
        return Err(DomainError::DuplicateBoardName { name: name.to_string() }.into());
    }

    let board_id = gen_id();
    let timestamp = now();
    let board = Board {
        id: board_id.clone(),
        name: name.to_string(),
        created_at: timestamp.clone(),
        updated_at: timestamp.clone(),
    };

    let default_columns = [
        ("Backlog", 0),
        ("Todo", 1),
        ("Doing", 2),
        ("Done", 3),
    ];
    let default_priorities = ["low", "medium", "high"];

    let tx = db
        .conn
        .transaction()
        .context("failed to begin transaction")?;

    // Insert board
    let (sql, params) = insert_board_sql(&board);
    exec_with_params_raw(&tx, &sql, &params)?;

    // Insert columns
    for (col_name, pos) in &default_columns {
        let col = Column {
            id: gen_id(),
            board_id: board_id.clone(),
            name: col_name.to_string(),
            position: *pos,
            created_at: timestamp.clone(),
            updated_at: timestamp.clone(),
        };
        let (sql, params) = insert_column_sql(&col);
        exec_with_params_raw(&tx, &sql, &params)?;
    }

    // Insert priorities
    for prio_name in &default_priorities {
        let prio = Priority {
            id: gen_id(),
            name: prio_name.to_string(),
        };
        let (sql, params) = insert_priority_sql(&prio);
        exec_with_params_raw(&tx, &sql, &params)?;
    }

    tx.commit().context("failed to commit transaction")?;

    Ok(board)
}

/// List all boards.
pub fn list_boards(db: &Db) -> Result<Vec<Board>> {
    db.list_boards()
}

/// Rename a board.
pub fn rename_board(db: &Db, board_id: &str, new_name: &str) -> Result<()> {
    let boards = db.list_boards()?;
    let resolved_id = resolve_id(board_id, &boards.iter().map(|b| b.id.as_str()).collect::<Vec<_>>())
        .map_err(|e| anyhow::anyhow!("{}", e))?;

    // Check for duplicate name (excluding this board)
    if boards.iter().any(|b| b.id != resolved_id && b.name == new_name) {
        return Err(DomainError::DuplicateBoardName { name: new_name.to_string() }.into());
    }

    let sql = "UPDATE board SET name = ?1, updated_at = ?2 WHERE id = ?3";
    db.conn.execute(
        sql,
        rusqlite::params![new_name, now(), resolved_id],
    ).context("failed to rename board")?;

    Ok(())
}

// ── Column operations ─────────────────────────────────────────────────────

/// Add a column to a board.
pub fn add_column(db: &Db, board_id: &str, name: &str) -> Result<Column> {
    validate_column_name(name, &[]).map_err(|e| anyhow::anyhow!("{}", e))?;

    let state = db.load_board_state(board_id)
        .map_err(|_| DomainError::BoardNotFound { id: board_id.to_string() })?;

    validate_column_name(name, &state.columns).map_err(|e| anyhow::anyhow!("{}", e))?;

    let positions: Vec<i32> = state.columns.iter().map(|c| c.position).collect();
    let next_pos = next_position(&positions);

    let column = Column {
        id: gen_id(),
        board_id: board_id.to_string(),
        name: name.to_string(),
        position: next_pos,
        created_at: now(),
        updated_at: now(),
    };

    let (sql, params) = insert_column_sql(&column);
    exec_with_params(&db.conn, &sql, &params)?;

    Ok(column)
}

/// Rename a column.
pub fn rename_column(db: &Db, column_id_prefix: &str, new_name: &str) -> Result<()> {
    validate_column_name(new_name, &[]).map_err(|e| anyhow::anyhow!("{}", e))?;

    let state = db.load_board_state_for_columns()?;
    let resolved_id = resolve_column_id(db, column_id_prefix, &state.columns)?;
    validate_column_name(new_name, &state.columns).map_err(|e| anyhow::anyhow!("{}", e))?;

    let sql = "UPDATE column_ SET name = ?1, updated_at = ?2 WHERE id = ?3";
    db.conn.execute(
        sql,
        rusqlite::params![new_name, now(), resolved_id],
    ).context("failed to rename column")?;

    Ok(())
}

/// Remove a column with the specified orphan action.
pub fn remove_column(db: &Db, column_id_prefix: &str, orphan_action: OrphanAction) -> Result<()> {
    let state = db.load_board_state_for_columns()?;
    let resolved_id = resolve_column_id(db, column_id_prefix, &state.columns)?;

    // Cannot delete the last column
    if state.columns.len() <= 1 {
        return Err(DomainError::CannotDeleteLastColumn.into());
    }

    // Count tasks in this column
    let task_count: i64 = db.conn.query_row(
        "SELECT COUNT(*) FROM task WHERE column_id = ?1",
        rusqlite::params![&resolved_id],
        |row| row.get(0),
    ).context("failed to count tasks")?;

    let tx = db.conn.transaction().context("failed to begin transaction")?;

    if task_count > 0 {
        match orphan_action {
            OrphanAction::MoveToFirst => {
                // Find the column that will have position 0 after deletion
                let remaining: Vec<Column> = state.columns.iter()
                    .filter(|c| c.id != resolved_id)
                    .cloned()
                    .collect();
                let sorted = recompute_positions(
                    &remaining.iter().map(|c| (c.id.clone(), c.position)).collect::<Vec<_>>()
                );
                // The first column after recomputation gets position 0
                let target_column_id = &sorted[0].0;

                // Move all tasks to the target column
                let (sql, params) = move_tasks_to_column_sql(&resolved_id, target_column_id);
                exec_with_params_raw(&tx, &sql, &params)?;

                // Recompute task positions in target column
                let target_tasks: Vec<(String, i32)> = tx.query_row(
                    "SELECT id, position FROM task WHERE column_id = ?1 ORDER BY position",
                    rusqlite::params![target_column_id],
                    |row| {
                        let mut tasks = Vec::new();
                        // This won't work directly, we need a different approach
                        Ok(tasks)
                    },
                ).unwrap_or_default();

                // Actually fetch tasks properly
                let mut stmt = tx.prepare(
                    "SELECT id, position FROM task WHERE column_id = ?1 ORDER BY position"
                ).context("failed to prepare task query")?;
                let task_rows = stmt.query_map(rusqlite::params![target_column_id], |row| {
                    Ok((row.get::<_, String>(0)?, row.get::<_, i32>(1)?))
                }).context("failed to query tasks")?;
                let task_rows: Vec<(String, i32)> = task_rows
                    .collect::<std::result::Result<Vec<_>, _>>()
                    .context("failed to collect tasks")?;
                let new_positions = recompute_positions(&task_rows);
                for (id, pos) in &new_positions {
                    let (sql, params) = update_position_sql(
                        crate::core::EntityTable::Task, id, *pos
                    );
                    exec_with_params_raw(&tx, &sql, &params)?;
                }
            }
            OrphanAction::Delete => {
                let (sql, params) = delete_tasks_by_column_sql(&resolved_id);
                exec_with_params_raw(&tx, &sql, &params)?;
            }
        }
    }

    // Delete the column
    let (sql, params) = delete_column_sql(&resolved_id);
    exec_with_params_raw(&tx, &sql, &params)?;

    // Recompute remaining column positions
    let remaining_columns: Vec<(String, i32)> = tx.prepare(
        "SELECT id, position FROM column_ WHERE board_id = (SELECT board_id FROM column_ WHERE id = ?1 LIMIT 1) ORDER BY position"
    ).context("failed to prepare column query")?
    .query_map(rusqlite::params![&resolved_id], |row| {
        Ok((row.get::<_, String>(0)?, row.get::<_, i32>(1)?))
    }).context("failed to query columns")?
    .collect::<std::result::Result<Vec<_>, _>>()
    .context("failed to collect columns")?;

    let new_positions = recompute_positions(&remaining_columns);
    for (id, pos) in &new_positions {
        let (sql, params) = update_position_sql(
            crate::core::EntityTable::Column, id, *pos
        );
        exec_with_params_raw(&tx, &sql, &params)?;
    }

    tx.commit().context("failed to commit transaction")?;

    Ok(())
}

/// Move a column to a new position.
pub fn move_column(db: &Db, column_id_prefix: &str, new_position: i32) -> Result<()> {
    let state = db.load_board_state_for_columns()?;
    let resolved_id = resolve_column_id(db, column_id_prefix, &state.columns)?;

    let max_pos = if state.columns.is_empty() { 0 } else { state.columns.len() as i32 };
    if new_position < 0 || new_position >= max_pos {
        return Err(DomainError::PositionOutOfRange {
            position: new_position,
            max: max_pos,
        }.into());
    }

    let column = state.columns.iter().find(|c| c.id == resolved_id).ok_or_else(|| {
        DomainError::ColumnNotFound { id: resolved_id.clone() }
    })?;

    let old_position = column.position;

    let tx = db.conn.transaction().context("failed to begin transaction")?;

    // Compute new positions for all columns
    let items: Vec<(String, i32)> = state.columns
        .iter()
        .map(|c| (c.id.clone(), c.position))
        .collect();

    use crate::core::positions_after_move;
    let new_positions = positions_after_move(&items, old_position, new_position);
    let new_positions = recompute_positions(&new_positions);

    for (id, pos) in &new_positions {
        let (sql, params) = update_position_sql(
            crate::core::EntityTable::Column, id, *pos
        );
        exec_with_params_raw(&tx, &sql, &params)?;
    }

    tx.commit().context("failed to commit transaction")?;

    Ok(())
}

/// List columns for a board.
pub fn list_columns(db: &Db, board_id: &str) -> Result<Vec<Column>> {
    let state = db.load_board_state(board_id)
        .map_err(|_| DomainError::BoardNotFound { id: board_id.to_string() })?;
    Ok(state.columns)
}

// ── Task operations ───────────────────────────────────────────────────────

/// Add a task to a column.
pub fn add_task(db: &Db, column_id_prefix: &str, title: &str, desc: &str, priority_id_prefix: &str) -> Result<Task> {
    validate_title(title).map_err(|e| anyhow::anyhow!("{}", e))?;

    let state = db.load_board_state_for_tasks()?;
    let resolved_column_id = resolve_column_id(db, column_id_prefix, &state.columns)?;
    validate_column_exists(&resolved_column_id, &state.columns).map_err(|e| anyhow::anyhow!("{}", e))?;

    // Resolve priority
    let resolved_priority_id = resolve_id(
        priority_id_prefix,
        &state.priorities.iter().map(|p| p.id.as_str()).collect::<Vec<_>>(),
    ).map_err(|e| anyhow::anyhow!("{}", e))?;

    validate_priority(&resolved_priority_id, &state.priorities).map_err(|e| anyhow::anyhow!("{}", e))?;

    // Find tasks in the target column to compute next position
    let column_tasks: Vec<Task> = state.tasks.iter()
        .filter(|t| t.column_id == resolved_column_id)
        .cloned()
        .collect();
    let positions: Vec<i32> = column_tasks.iter().map(|t| t.position).collect();
    let next_pos = next_position(&positions);

    let task = Task {
        id: gen_id(),
        column_id: resolved_column_id,
        title: title.to_string(),
        description: desc.to_string(),
        priority_id: resolved_priority_id,
        position: next_pos,
        created_at: now(),
        updated_at: now(),
    };

    let (sql, params) = insert_task_sql(&task);
    exec_with_params(&db.conn, &sql, &params)?;

    Ok(task)
}

/// Edit a task.
pub fn edit_task(db: &Db, task_id_prefix: &str, changes: &TaskChanges) -> Result<()> {
    let state = db.load_board_state_for_tasks()?;
    let resolved_id = resolve_task_id(db, task_id_prefix, &state.tasks)?;

    // Validate priority if changed
    if let Some(ref priority_id) = changes.priority_id {
        validate_priority(priority_id, &state.priorities)
            .map_err(|e| anyhow::anyhow!("{}", e))?;
    }

    // Validate column if changed
    if let Some(ref column_id) = changes.column_id {
        validate_column_exists(column_id, &state.columns)
            .map_err(|e| anyhow::anyhow!("{}", e))?;
    }

    // Validate title if changed
    if let Some(ref title) = changes.title {
        validate_title(title)
            .map_err(|e| anyhow::anyhow!("{}", e))?;
    }

    let (sql, params) = update_task_sql(&resolved_id, changes);
    exec_with_params(&db.conn, &sql, &params)?;

    Ok(())
}

/// Move a task to a different column/position.
pub fn move_task(db: &Db, task_id_prefix: &str, target_column_prefix: &str, position: Option<i32>) -> Result<()> {
    let state = db.load_board_state_for_tasks()?;
    let resolved_task_id = resolve_task_id(db, task_id_prefix, &state.tasks)?;
    let resolved_column_id = resolve_column_id(db, target_column_prefix, &state.columns)?;

    let task = state.tasks.iter().find(|t| t.id == resolved_task_id).ok_or_else(|| {
        DomainError::TaskNotFound { id: resolved_task_id.clone() }
    })?;

    let tx = db.conn.transaction().context("failed to begin transaction")?;

    let target_position = if let Some(pos) = position {
        pos
    } else {
        // Append at end of target column
        let target_tasks: Vec<i32> = state.tasks.iter()
            .filter(|t| t.column_id == resolved_column_id && t.id != resolved_task_id)
            .map(|t| t.position)
            .collect();
        next_position(&target_tasks)
    };

    let new_column_id = resolved_column_id;
    let old_column_id = task.column_id.clone();

    let sql = "UPDATE task SET column_id = ?1, position = ?2, updated_at = ?3 WHERE id = ?4";
    tx.execute(
        sql,
        rusqlite::params![new_column_id, target_position, now(), resolved_task_id],
    ).context("failed to move task")?;

    tx.commit().context("failed to commit transaction")?;

    Ok(())
}

/// Remove a task.
pub fn remove_task(db: &Db, task_id_prefix: &str) -> Result<()> {
    let state = db.load_board_state_for_tasks()?;
    let resolved_id = resolve_task_id(db, task_id_prefix, &state.tasks)?;

    let (sql, params) = delete_task_sql(&resolved_id);
    exec_with_params(&db.conn, &sql, &params)?;

    Ok(())
}

/// Show a single task.
pub fn show_task(db: &Db, task_id_prefix: &str) -> Result<Task> {
    let state = db.load_board_state_for_tasks()?;
    let resolved_id = resolve_task_id(db, task_id_prefix, &state.tasks)?;

    state.tasks.iter()
        .find(|t| t.id == resolved_id)
        .cloned()
        .ok_or_else(|| anyhow::anyhow!("task not found: '{}'", resolved_id))
}

/// List tasks with optional filtering.
pub fn list_tasks(db: &Db, board_id: &str, filter: &TaskFilter) -> Result<Vec<Task>> {
    let state = db.load_board_state(board_id)
        .map_err(|_| DomainError::BoardNotFound { id: board_id.to_string() })?;

    let mut tasks = state.tasks;

    // Apply column filter
    if let Some(ref col_id) = filter.column_id {
        // Resolve column prefix
        let resolved_col_id = resolve_id(
            col_id,
            &state.columns.iter().map(|c| c.id.as_str()).collect::<Vec<_>>(),
        ).map_err(|e| anyhow::anyhow!("{}", e))?;
        tasks.retain(|t| t.column_id == resolved_col_id);
    }

    // Apply priority filter
    if let Some(ref prio_id) = filter.priority_id {
        let resolved_prio_id = resolve_id(
            prio_id,
            &state.priorities.iter().map(|p| p.id.as_str()).collect::<Vec<_>>(),
        ).map_err(|e| anyhow::anyhow!("{}", e))?;
        tasks.retain(|t| t.priority_id == resolved_prio_id);
    }

    Ok(tasks)
}

