fn exec_with_params_raw(
    conn: &rusqlite::Transaction,
    sql: &str,
    params: &[SqlParam],
) -> Result<()> {
    let rusqlite_params: Vec<&dyn rusqlite::types::ToSql> = params
        .iter()
        .map(|p| match p {
            SqlParam::Text(s) => s as &dyn rusqlite::types::ToSql,
            SqlParam::Int(i) => i as &dyn rusqlite::types::ToSql,
        })
        .collect();
    let mut stmt = conn
        .prepare(sql)
        .context("failed to prepare statement")?;
    stmt.execute(rusqlite::params_from_iter(rusqlite_params.iter().copied()))
        .context("failed to execute statement")?;
    Ok(())
}

fn resolve_column_id(db: &Db, prefix: &str, columns: &[Column]) -> Result<String> {
    let ids: Vec<&str> = columns.iter().map(|c| c.id.as_str()).collect();

    // Try ID resolution first
    if let Ok(id) = resolve_id(prefix, &ids) {
        return Ok(id);
    }

    // Fall back to case-insensitive name matching
    let matches: Vec<&Column> = columns.iter()
        .filter(|c| c.name.eq_ignore_ascii_case(prefix))
        .collect();

    match matches.len() {
        0 => Err(DomainError::ColumnNotFound { id: prefix.to_string() }.into()),
        1 => Ok(matches[0].id.clone()),
        _ => Err(anyhow!("multiple columns match name '{}'", prefix)),
    }
}

fn resolve_task_id(db: &Db, prefix: &str, tasks: &[Task]) -> Result<String> {
    let ids: Vec<&str> = tasks.iter().map(|t| t.id.as_str()).collect();
    resolve_id(prefix, &ids).map_err(|e| anyhow::anyhow!("{}", e))
}

/// Load board state sufficient for column operations (columns + board).
fn load_board_state_for_columns(&self) -> Result<BoardState> {
    // Load all board states; for now we support single-board, so take the first
    let boards = self.list_boards()?;
    let board = boards.first().ok_or_else(|| {
        anyhow::anyhow!("no boards found; run 'init' first")
    })?;

    let columns = self.query_columns(&board.id)?;
    let tasks = self.query_tasks(&board.id)?;
    let priorities = self.query_priorities()?;

    Ok(BoardState {
        board: board.clone(),
        columns,
        tasks,
        priorities,
    })
}

/// Load board state sufficient for task operations (all data).
fn load_board_state_for_tasks(&self) -> Result<BoardState> {
    self.load_board_state_for_columns()
}

